/**
 * In development, Gatsby proxies `/api` to the Express server.
 * In production, set GATSBY_API_URL to your API origin (no trailing slash).
 */
export function apiUrl(path) {
  const base =
    typeof process !== `undefined` && process.env.GATSBY_API_URL
      ? String(process.env.GATSBY_API_URL).replace(/\/$/, ``)
      : ``
  if (!path.startsWith(`/`)) return `${base}/${path}`
  return base ? `${base}${path}` : path
}

export async function apiJson(path, options = {}) {
  const res = await fetch(apiUrl(path), {
    ...options,
    headers: {
      "Content-Type": `application/json`,
      ...(options.headers || {}),
    },
  })
  const text = await res.text()
  let data = null
  try {
    data = text ? JSON.parse(text) : null
  } catch {
    data = text
  }
  if (!res.ok) {
    const err = new Error((data && data.error) || res.statusText || `Request failed`)
    err.status = res.status
    err.body = data
    throw err
  }
  return data
}
